r_","type":"address"},{"internalType":"address","name":"createdBy_","type":"address"}],"name":"notifyLockerOwnerChange","outputs":[],"stateMutability":"nonpayable","type":"function"},{"inputs":[],"name":"owner","outputs":[{"internalType":"address","name":"","type":"address"}],"stateMutability":"view","type":"function"},{"inputs":[{"internalType":"address","name":"positionManager_","type":"address"}],"name":"positionManagerKind","outputs":[{"internalType":"enum ITitanLockerManagerV2.LockKind","name":"kind","type":"uint8"},{"internalType":"bool","name":"allowed","type":"bool"}],"stateMutability":"view","type":"function"},{"inputs":[{"internalType":"bool","name":"value_","type":"bool"}],"name":"setCreationEnabled","outputs":[],"stateMutability":"nonpayable","type":"function"},{"inputs":[{"internalType":"uint256","name":"value_","type":"uint256"}],"name":"setEthFee","outputs":[],"stateMutability":"nonpayable","type":"function"},{"inputs":[{"internalType":"address","name":"account_","type":"address"},{"internalType":"bool","name":"exempt_","type":"bool"}],"name":"setFeeExempt","outputs":[],"stateMutability":"nonpayable","type":"function"},{"inputs":[{"internalType":"address payable","name":"value_","type":"address"}],"name":"setFeeReceiver","outputs":[],"stateMutability":"nonpayable","type":"function"},{"inputs":[{"internalType":"address","name":"positionManager_","type":"address"},{"internalType":"enum ITitanLockerManagerV2.LockKind","name":"kind_","type":"uint8"},{"internalType":"bool","name":"allowed_","type":"bool"}],"name":"setPositionManager","outputs":[],"stateMutability":"nonpayable","type":"function"},{"inputs":[{"internalType":"uint16","name":"value_","type":"uint16"}],"name":"setTokenFeeBps","outputs":[],"stateMutability":"nonpayable","type":"function"},{"inputs":[],"name":"tokenFeeBps","outputs":[{"internalType":"uint16","name":"","type":"uint16"}],"stateMutability":"view","type":"function"},{"inputs":[],"name":"tokenLockerCount","outputs":[{"internalType":"uint40","name":"","type":"uint40"}],"stateMutability":"view","type":"function"},{"inputs":[{"internalType":"address","name":"newOwner_","type":"address"}],"name":"transferOwnership","outputs":[],"stateMutability":"nonpayable","type":"function"}],"devdoc":{"errors":{"ReentrancyGuardReentrantCall()":[{"details":"Unauthorized reentrant call."}],"SafeERC20FailedOperation(address)":[{"details":"An operation with an ERC-20 token failed."}]},"kind":"dev","methods":{"createPositionLock(address,uint256,uint40)":{"details":"Uniswap V3/V4 path. `positionManager_` must be allowlisted; its registered kind decides how fees are later collected. Only the flat `ethFee()` applies (a percentage of an NFT is not possible). The caller must have approved this manager as an operator for the position NFT."},"createTokenLock(address,uint256,uint40,uint16)":{"details":"ERC20 (and V2-LP) path. Two ways to pay the creation fee: send `ethFee()` wei to lock 100% of `amount_`, or send 0 wei and have `tokenFeeBps()` deducted from `amount_` in the locked token itself - in which case the call reverts if the live `tokenFeeBps()` exceeds `maxTokenFeeBps_` (ignored on the ETH-fee path), protecting the caller against a fee change landing between submission and mining. Pass `type(uint16).max` to accept whatever the live rate is."},"createVestingLock(address,uint256,uint40,uint40,uint40,uint16)":{"details":"Locks a fungible token and releases it linearly (with an optional cliff) to the lock owner between `start_` and `end_`. Same creation-fee options as `createTokenLock`; the vesting grant is the post-fee amount and is irrevocable."},"notifyLockerOwnerChange(uint40,address,address,address)":{"details":"Called by a `TitanLockerV2` whenever its ownership changes, so the search index above stays accurate."},"setCreationEnabled(bool)":{"details":"Turns off new locks so users can be migrated to a future version. Existing locks keep working (extend/deposit/withdraw/collect) as normal."},"setPositionManager(address,uint8,bool)":{"details":"Allowlist (or update/remove) a position manager. `kind_` must be UNIV3 or UNIV4. Set `allowed_` false to disable it for new locks."},"transferOwnership(address)":{"details":"Reverts on a zero-address target so ownership can never be bricked by accident; there is deliberately no "renounce ownership" escape hatch."}},"stateVariables":{"MAX_TOKEN_FEE_BPS":{"details":"Hard ceiling on the owner-settable token fee, independent of any caller-side slippage protection. Bounds the worst case of a fee change landing between a user's createTokenLock/createVestingLock submission and its mining: at most 5% of the deposit, never up to 100%."},"_pmKind":{"details":"Allowlist of Uniswap position managers. `_pmKind` records whether a manager is V3- or V4-style; `_pmAllowed` gates whether new locks may use it. A manager with `_pmAllowed == false` is rejected regardless of kind."},"_tokenLockersForAddress":{"details":"Lets the frontend search lockers by creator, locked token/position manager, locker address, or either underlying paired token."}},"version":1},"userdoc":{"kind":"user","methods":{"positionManagerKind(address)":{"notice":"Kind registered for a position manager and whether it is allowed. `allowed_ == false` means positions cannot be locked against it."}},"notice":"Deploys and indexes `TitanLockerV2` instances for three lock kinds - plain/LP ERC20 tokens, Uniswap V3 positions, and Uniswap V4 positions - all through one manager. Each lock is its own child contract, so custody is isolated per lock. V3/V4 positions can only be locked against a position manager the owner has allowlisted, which is both the multichain mechanism and the kill-switch for un-validated integrations.","version":1}},"settings":{"compilationTarget":{"contracts/TitanLockerManagerV2.sol":"TitanLockerManagerV2"},"evmVersion":"london","libraries":{},"metadata":{"bytecodeHash":"ipfs","useLiteralContent":true},"optimizer":{"enabled":true,"runs":200},"remappings":[]},"sources":{"@open